sql:
SELECT vehicle_type, COUNT(vehicle_id) AS vehicle_count
FROM vehicles
GROUP BY vehicle_type;

external_knowledge:
- "Vessels" metaphorically refers to the vehicles in the `vehicles` table;
- "Sailed the seas" metaphorically refers to vehicles that have participated in flights;
- "Number of voyages undertaken" refers to the count of flights associated with each vehicle.

sql:
SELECT vehicle_name
FROM vehicles
WHERE status = 'maintenance';
